module.render:
    const color = args.color || 'var(--accent-color)';
    const termStr = sections[0] ? sections[0].trim() : '';
    const defStr = sections[1] ? sections[1].trim() : '';
    return `

<div class="mdp-mod-definition"><div class="definition-term" style="color: ${color};">

${termStr}

</div><div class="definition-body" style="border-left-color: ${color};">

${defStr}

</div></div>

`;
